import React from 'react'
import BannerImage from "../assets/Bekaa.jpg";
import "../styles/Home.css";

const Home = () => {
  return (
    <div className="home" style={{ backgroundImage: `url(${BannerImage})` }}>
      <div className="headerContainer">
        <h1> Bekaa Campus </h1>
      </div>
    </div>

  )
}

export default Home
